// Package integrations aggregates the pulumi run funcs for agent-integrations
// E2E labs generated by agint:generate-lab. Each lab registers its scenario
// under the "aws/integrations/<integration>" key.
package integrations

import (
	sapabap "github.com/DataDog/datadog-agent/test/e2e-framework/scenarios/aws/integrations/sap_abap"
	sapalm "github.com/DataDog/datadog-agent/test/e2e-framework/scenarios/aws/integrations/sap_alm"

	"github.com/pulumi/pulumi/sdk/v3/go/pulumi"
)

// Scenarios returns the map of integration-lab scenario keys to their pulumi run funcs.
func Scenarios() map[string]pulumi.RunFunc {
	return map[string]pulumi.RunFunc{
		"aws/integrations/sap_alm":  sapalm.VMRun,
		"aws/integrations/sap_abap": sapabap.VMRun,
	}
}
